mapper.insert:
/** CmmtEmailDao.insert */
insert into cmmt_email (
	 email_id
	,title
	,article
	,html
	,send
	,send_dt
	,try_cnt
	,system_id
	,created_dt
) values (
	 #{emailId}
	,#{title}
	,#{article}
	,#{html}
	,#{send}
	,#{sendDt}
	,#{tryCnt}
	,#{systemId}
	,#{createdDt}
)

/** CmmtEmailDao.insertList */
insert into cmmt_email (
	 email_id
	,title
	,article
	,html
	,send
	,send_dt
	,try_cnt
	,system_id
	,created_dt
) values

	(
		 #{item.emailId}
		,#{item.title}
		,#{item.article}
		,#{item.html}
		,#{item.send}
		,#{item.sendDt}
		,#{item.tryCnt}
		,#{item.systemId}
		,#{item.createdDt}
	)

mapper.update:
/** CmmtEmailDao.update */
update cmmt_email set
	 title      = #{title}
	,article    = #{article}
	,html       = #{html}
	,send       = #{send}
	,send_dt    = #{sendDt}
	,try_cnt    = #{tryCnt}
	,system_id  = #{systemId}
	,created_dt = #{createdDt}
where
	email_id = #{emailId}

mapper.delete:
/** CmmtEmailDao.delete */
delete from
	cmmt_email
where
	email_id = #{emailId}

mapper.select:
/** CmmtEmailDao.select */
select

from
	cmmt_email
where
	email_id = #{emailId}

/** CmmtEmailDao.selectList_notSent */
select

from
	cmmt_email
where

	send = false
	and created_dt >= #{fromDt}
	and try_cnt < #{maxTryCnt}

order by
	created_dt

mapper.delete:
/** CmmtEmailDao.delete_old */
delete from
	cmmt_email
where

	created_dt <= #{dtime}
